import { BadgeComponent } from './badge.component';
const meta = {
    title: 'Design System/Badge',
    component: BadgeComponent,
    tags: ['autodocs'],
    argTypes: {
        status: {
            control: 'select',
            options: ['info', 'success', 'warning', 'error', 'neutral'],
        },
        style: {
            control: 'select',
            options: ['light', 'strong'],
        },
        size: {
            control: 'select',
            options: ['s', 'm'],
        },
    },
};
export default meta;
export const Default = {
    args: { status: 'info', style: 'light', size: 's' },
    render: (args) => ({
        props: args,
        template: `<ds-badge [status]="status" [style]="style" [size]="size">En cours</ds-badge>`,
    }),
};
export const AllStatuses = {
    render: () => ({
        template: `
      <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;">
        <ds-badge status="info"    style="light" size="s">Info</ds-badge>
        <ds-badge status="success" style="light" size="s">Succès</ds-badge>
        <ds-badge status="warning" style="light" size="s">Attention</ds-badge>
        <ds-badge status="error"   style="light" size="s">Erreur</ds-badge>
        <ds-badge status="neutral" style="light" size="s">Neutre</ds-badge>
      </div>
    `,
    }),
};
export const StrongStyle = {
    render: () => ({
        template: `
      <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;">
        <ds-badge status="info"    style="strong" size="s">Info</ds-badge>
        <ds-badge status="success" style="strong" size="s">Succès</ds-badge>
