        <ds-badge status="neutral" style="strong" size="s">Neutre</ds-badge>
      </div>
    `,
    }),
};
export const SizeMedium = {
    render: () => ({
        template: `
      <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;">
        <ds-badge status="info"    style="light" size="m">Info M</ds-badge>
        <ds-badge status="success" style="light" size="m">Succès M</ds-badge>
        <ds-badge status="error"   style="strong" size="m">Erreur M</ds-badge>
      </div>
    `,
    }),
};
